VALUES
  ('elementary-10ced7e2-moex-00571', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-112-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '稱不動產役權者，謂以他人不動產供自己不動產通行、汲水、採光、眺望、電信或其他以特定便宜 之用為目的之權。下列關於不動產役權之敘述，何者錯誤？', '["不動產役權因時效而取得者，以繼續並表見者為限", "不動產役權不得由需役不動產分離而為讓與，或為其他權利之標的物", "不動產役權，不得就自己之不動產設定之", "不動產役權人因行使權利而為設置者，有維持其設置之義務"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:46+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "505", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00572', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-112-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '依民法規定，下列何者非姻親關係？', '["血親之配偶", "配偶之血親", "血親之配偶之血親", "配偶之血親之配偶"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:46+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "505", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00573', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-112-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '設有爸爸甲、媽媽乙、讀國小的兒子丙與女兒丁，以及爺爺戊等人。下列何者非屬民法規定有關甲 乙對於未成年子女丙丁所為之財產上行為？', '["甲騎著學校送給丙作為模範生獎品之腳踏車上班", "乙強制把丁過年獲得之紅包存在丁之郵局帳戶", "甲開工廠要向銀行借錢，拿戊遺贈給丙之房子為銀行設定普通抵押權", "乙在戊遺贈給丁之農地上經營種苗場"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:46+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "505", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 38, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00574', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-112-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '關於限制辯護人與被告接見，下列敘述何者正確？', '["司法警察官得聲請限制辯護人與羈押之被告接見", "法院核發限制書，應經法官簽名", "檢察官也可以核發限制書", "對於辯護人與受逮捕的被告互通書信，得限制之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:46+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "505", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00575', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-112-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '有關刑事被告自白證明力之敘述，下列何者正確？', '["被告之自白，得作為被告有罪判決之唯一證據", "被告自白之證據能力與證明力為相同的概念", "告訴人經改列證人到庭具結之證言，得作為被告自白之補強證據", "被告自白之補強證據，以能證明被告全部犯罪事實為必要"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:46+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "505", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00576', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-112-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '下列關於證據之敘述，何者正確？', '["有證據能力之證據，即可作為判斷被告是否有罪之依據", "經過合法調查之證據，即可作為判斷被告是否有罪之依據", "那些證據可以判斷被告是否有罪，全憑法院決定", "有證據能力且經合法調查之證據，即可作為判斷被告是否有罪之依據"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:46+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "505", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00577', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-112-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '檢察官起訴被告涉犯傷害罪嫌，但法院進行審判程序時，認被告之傷害行為應構成重傷害未遂罪， 且依照起訴書記載之犯罪事實，被告另涉及妨害自由行為。依實務見解，此時法院應如何處理？', '["法院僅依起訴罪名審理並終結案件為已足", "基於不告不理原則，妨害自由部分未起訴，法院毋庸審理", "法院應告知被告原先起訴之傷害罪名可能變更為重傷害未遂罪名，且應一併審理妨害自由部分， 同時告知被告尚涉及妨害自由之犯罪嫌疑及罪名", "法院應曉諭檢察官追加起訴妨害自由部分，始得加以審理"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:46+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "505", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00578', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-112-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '下列關於刑法第23條正當防衛之敘述，何者錯誤？', '["須對於現在不法之侵害為之", "須為出於防衛自己或他人權利之行為", "防衛行為如過當，則僅得減輕或免除其刑", "僅得對於侵害自己或他人生命、身體、自由、財產等權利之行為而為防衛行為"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:46+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "505", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00579', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-112-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '下列關於刑法上公務員之敘述，何者錯誤？', '["任職於公立醫院之醫師，就其日常提供之醫療服務並非公權力之行使，並非身分公務員", "若醫師依法令從事於公共事務，而具法定職務權限時，仍應認其屬於授權公務員", "替代役役男服役期間，比照現役軍人身分，絕對是公務員", "替代役之警察役別，奉派往監獄擔任崗哨、巡邏勤務者，應視為刑法上之公務員"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:46+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "505", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00580', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-112-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '某甲參加公務人員考試時，以電子舞弊方式因而通過考試，甲有無犯罪？', '["構成刑法第339條之詐欺罪", "構成刑法第137條之以詐術使考試發生不正確結果罪", "偽造文書罪", "不犯罪"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:46+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "505", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL)
